import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import ModernDashboard from './components/ModernDashboard';
import Animals from './components/Animals';
import Reproduction from './components/Reproduction';
import Locations from './components/Locations';
import Weights from './components/Weights';
import Health from './components/Health';
import Finance from './components/Finance';
import Reports from './components/Reports';
import Analytics from './components/Analytics';
import Genealogy from './components/Genealogy';
import NutritionComplete from './components/NutritionComplete';
import UserManagement from './components/UserManagement';
import NotificationCenter from './components/NotificationCenter';
import UserProfile from './components/UserProfile';
import Sidebar from './components/Sidebar';
import ErrorBoundary from './components/ErrorBoundary';
import { AuthProvider, useAuth } from './context/AuthContext';
import { NotificationProvider } from './components/NotificationSystem';
import './App.css';
import './styles/global.css';

const AppContent: React.FC = () => {
  const { user, loading } = useAuth();

  if (loading) {
    return <div className="loading">Cargando...</div>;
  }

  if (!user) {
    return <Login />;
  }

  return (
    <div className="main-wrapper">
      <Sidebar />
      <div className="main-panel">
        <div className="main-header">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <h4 style={{ margin: 0, color: '#1a2035', fontWeight: '600' }}>Dashboard</h4>
            <div className="navbar-nav">
              <div className="nav-item dropdown">
                <button 
                  className="nav-link dropdown-toggle"
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: '10px',
                    background: 'none',
                    border: 'none',
                    padding: '8px 15px',
                    borderRadius: '25px',
                    cursor: 'pointer',
                    transition: 'all 0.3s ease'
                  }}
                  onMouseEnter={(e) => e.currentTarget.style.background = '#f8f9fa'}
                  onMouseLeave={(e) => e.currentTarget.style.background = 'none'}
                >
                  <div style={{
                    width: '35px',
                    height: '35px',
                    borderRadius: '50%',
                    background: 'linear-gradient(135deg, #1572e8, #0d47a1)',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    color: '#ffffff',
                    fontSize: '14px',
                    fontWeight: '600'
                  }}>
                    {user.nombre?.charAt(0).toUpperCase()}
                  </div>
                  <div style={{ textAlign: 'left' }}>
                    <div style={{ fontSize: '14px', fontWeight: '600', color: '#1a2035' }}>
                      {user.nombre}
                    </div>
                    <div style={{ fontSize: '12px', color: '#6c757d', textTransform: 'capitalize' }}>
                      {user.rol}
                    </div>
                  </div>
                  <i className="fas fa-chevron-down" style={{ fontSize: '10px', color: '#6c757d' }}></i>
                </button>
              </div>
            </div>
          </div>
        </div>
        <div className="page-inner">
          <Routes>
            <Route path="/" element={<ModernDashboard />} />
            <Route path="/animals" element={<Animals />} />
            <Route path="/reproduction" element={<Reproduction />} />
            <Route path="/locations" element={<Locations />} />
            <Route path="/weights" element={<Weights />} />
            <Route path="/health" element={<Health />} />
            <Route path="/finance" element={<Finance />} />
            <Route path="/reports" element={<Reports />} />
            <Route path="/analytics" element={<Analytics />} />
            <Route path="/genealogy" element={<Genealogy />} />
            <Route path="/nutrition" element={<NutritionComplete />} />
            <Route path="/users" element={<UserManagement />} />
            <Route path="/notifications" element={<NotificationCenter />} />
            <Route path="/profile" element={<UserProfile />} />
            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </div>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <ErrorBoundary>
      <NotificationProvider>
        <AuthProvider>
          <Router>
            <AppContent />
          </Router>
        </AuthProvider>
      </NotificationProvider>
    </ErrorBoundary>
  );
};

export default App;
